'use client';

import { useState, useEffect, useCallback, useMemo } from 'react';
import { motion } from 'framer-motion';
import dynamic from 'next/dynamic';
import { MovebankStudy, AnimalTrack } from '../types/movebank';
import { movebankService } from '../services/movebank';
import AnimalProfile from '../components/ui/AnimalProfile';
import AlertsPanel from '../components/ui/AlertsPanel';
import ComparisonPanel from '../components/ui/ComparisonPanel';
import Charts from '../components/ui/Charts';
import PlaybackControls from '../components/ui/PlaybackControls';
import { exportToCSV, exportToJSON, exportToGeoJSON } from '../lib/export';
import { COUNTRIES } from '../components/globe/Globe';

const Globe = dynamic(() => import('../components/globe/Globe'), {
  ssr: false,
  loading: () => (
    <div className="w-full h-full flex items-center justify-center text-white">
      <motion.div
        animate={{ rotate: 360 }}
        transition={{ duration: 2, repeat: Infinity, ease: 'linear' }}
        className="text-4xl"
      >
        🌍
      </motion.div>
    </div>
  ),
});

const DEFAULT_STUDY_ID = 2911040;

export default function Home() {
  const [studies, setStudies] = useState<MovebankStudy[]>([]);
  const [selectedStudyIds, setSelectedStudyIds] = useState<number[]>([]);
  const [animalTracks, setAnimalTracks] = useState<AnimalTrack[]>([]);
  const [selectedAnimal, setSelectedAnimal] = useState<string | null>(null);
  const [comparisonMode, setComparisonMode] = useState(false);
  const [comparisonAnimals, setComparisonAnimals] = useState<Set<string>>(new Set());
  const [showCities, setShowCities] = useState(true);
  const [showAlerts, setShowAlerts] = useState(false);
  const [loading, setLoading] = useState(true);
  const [playbackProgress, setPlaybackProgress] = useState(1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [rotationSpeed, setRotationSpeed] = useState(0);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSpecies, setSelectedSpecies] = useState<string>('');
  const [selectedCountryIdx, setSelectedCountryIdx] = useState<number | null>(null);

  useEffect(() => {
    document.title = 'WorldView 3D';
  }, []);

  useEffect(() => {
    loadStudies();
    setSelectedStudyIds([DEFAULT_STUDY_ID]);
    loadStudyData([DEFAULT_STUDY_ID]);
  }, []);

  const loadStudies = async () => {
    try {
      const data = await movebankService.getPublicStudies();
      setStudies(data);
    } catch (error) {
      console.error('Failed to load studies:', error);
    }
  };

  const loadStudyData = async (studyIds: number[]) => {
    setLoading(true);
    try {
      const allTracks: AnimalTrack[] = [];
      for (const id of studyIds) {
        const events = await movebankService.getStudyEvents(id);
        const tracks = movebankService.transformToAnimalTracks(events);
        allTracks.push(...tracks);
      }
      setAnimalTracks(allTracks);
    } catch (error) {
      console.error('Failed to load animal data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleStudySelect = (studyId: number) => {
    setSelectedStudyIds(prev => {
      if (prev.includes(studyId)) {
        return prev.filter(id => id !== studyId);
      }
      return [...prev, studyId];
    });
  };

  useEffect(() => {
    if (selectedStudyIds.length > 0) {
      loadStudyData(selectedStudyIds);
    } else {
      setAnimalTracks([]);
    }
  }, [selectedStudyIds]);

  const handleAnimalClick = useCallback((track: AnimalTrack) => {
    if (comparisonMode) {
      setComparisonAnimals(prev => {
        const next = new Set(prev);
        if (next.has(track.animalId)) {
          next.delete(track.animalId);
        } else {
          next.add(track.animalId);
        }
        return next;
      });
    } else {
      setSelectedAnimal(track.animalId);
    }
  }, [comparisonMode]);

  const speciesList = useMemo(() => {
    const species = new Set(animalTracks.map(t => t.species).filter(Boolean));
    return Array.from(species);
  }, [animalTracks]);

  const filteredTracks = useMemo(() => {
    return animalTracks.filter(track => {
      if (searchTerm && !track.animalName.toLowerCase().includes(searchTerm.toLowerCase())) return false;
      if (selectedSpecies && track.species !== selectedSpecies) return false;
      return true;
    });
  }, [animalTracks, searchTerm, selectedSpecies]);

  const selectedTrack = filteredTracks.find(t => t.animalId === selectedAnimal) || null;
  const startDate = selectedTrack?.points[0]?.timestamp || '';
  const endDate = selectedTrack?.points[selectedTrack.points.length - 1]?.timestamp || '';

  return (
    <main className="w-full h-screen bg-[#0a0a1a] relative overflow-hidden">
      <div className="absolute inset-0 z-0">
        {loading ? (
          <div className="w-full h-full flex items-center justify-center text-white">
            <motion.div
              animate={{ opacity: [0.5, 1, 0.5] }}
              transition={{ duration: 1.5, repeat: Infinity }}
              className="text-xl"
            >
              Loading wildlife tracking data...
            </motion.div>
          </div>
        ) : (
          <Globe
            animalTracks={filteredTracks}
            selectedAnimal={selectedAnimal}
            onAnimalSelect={setSelectedAnimal}
            playbackProgress={playbackProgress}
            showCities={showCities}
            selectedCountry={selectedCountryIdx}
            onCountrySelect={(idx: number | null) => setSelectedCountryIdx(idx)}
            isPlaying={isPlaying}
            rotationSpeed={rotationSpeed}
          />
        )}
      </div>

      <div className="absolute top-6 left-6 z-10 space-y-3">
        {selectedTrack && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
          >
            <Charts track={selectedTrack} playbackProgress={playbackProgress} />
          </motion.div>
        )}

        {comparisonMode && comparisonAnimals.size >= 2 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
          >
            <ComparisonPanel
              tracks={filteredTracks.filter(t => comparisonAnimals.has(t.animalId))}
            />
          </motion.div>
        )}

        {showAlerts && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
          >
            <AlertsPanel
              tracks={filteredTracks}
              onClose={() => setShowAlerts(false)}
            />
          </motion.div>
        )}
      </div>

      <div className="absolute top-6 right-6 z-10 space-y-3">
        {selectedTrack && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
          >
            <AnimalProfile
              track={selectedTrack}
              onClose={() => setSelectedAnimal(null)}
              playbackProgress={playbackProgress}
            />
          </motion.div>
        )}
      </div>

      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-10">
        <PlaybackControls
          isPlaying={isPlaying}
          progress={playbackProgress}
          onPlayPause={() => setIsPlaying(!isPlaying)}
          onProgressChange={setPlaybackProgress}
          currentTime={selectedTrack?.points[Math.floor(selectedTrack.points.length * playbackProgress)]?.timestamp ? new Date(selectedTrack.points[Math.floor(selectedTrack.points.length * playbackProgress)].timestamp).toLocaleTimeString() : '--:--:--'}
          totalTime={selectedTrack?.points[selectedTrack.points.length - 1]?.timestamp ? new Date(selectedTrack.points[selectedTrack.points.length - 1].timestamp).toLocaleTimeString() : '--:--:--'}
          startDate={startDate}
          endDate={endDate}
          rotationSpeed={rotationSpeed}
          onRotationSpeedChange={(speed: number) => {
            setRotationSpeed(speed);
            if (speed === 0) setIsPlaying(false);
            else setIsPlaying(true);
          }}
        />
      </div>

      <motion.div
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.7 }}
        className="absolute top-6 left-1/2 -translate-x-1/2 z-10"
      >
        <h1 className="text-2xl font-bold text-white tracking-wide" style={{ textShadow: '0 0 20px rgba(0,136,255,0.8), 0 0 40px rgba(0,136,255,0.4)' }}>
          WorldView 3D
        </h1>
      </motion.div>

      {selectedCountryIdx !== null && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center"
          onClick={() => setSelectedCountryIdx(null)}
        >
          <div
            className="relative"
            onClick={(e) => e.stopPropagation()}
            style={{
              color: '#00aaff',
              fontSize: '16px',
              fontWeight: 'bold',
              whiteSpace: 'normal',
              userSelect: 'none',
              background: 'rgba(0, 20, 40, 0.85)',
              backdropFilter: 'blur(20px)',
              WebkitBackdropFilter: 'blur(20px)',
              padding: '30px',
              borderRadius: '20px',
              border: '1px solid rgba(0, 170, 255, 0.5)',
              minWidth: '500px',
              maxWidth: '600px',
              boxShadow: '0 20px 60px rgba(0, 170, 255, 0.4), inset 0 1px 0 rgba(255, 255, 255, 0.2)',
            }}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px', borderBottom: '1px solid rgba(0, 170, 255, 0.4)', paddingBottom: '10px' }}>
              <span style={{ fontSize: '24px', textShadow: '0 0 20px #00aaff' }}>{COUNTRIES[selectedCountryIdx].name}</span>
              <button
                onClick={() => setSelectedCountryIdx(null)}
                style={{
                  background: 'rgba(0, 170, 255, 0.4)',
                  border: '1px solid rgba(0, 170, 255, 0.6)',
                  color: '#00aaff',
                  cursor: 'pointer',
                  fontSize: '28px',
                  lineHeight: '1',
                  padding: '6px 16px',
                  borderRadius: '10px',
                  backdropFilter: 'blur(4px)',
                }}
              >
                ×
              </button>
            </div>
            <div style={{ fontWeight: 'normal', fontSize: '15px', lineHeight: '2', color: 'rgba(255, 255, 255, 1)' }}>
              <div style={{ marginBottom: '8px', fontSize: '12px', color: 'rgba(0, 170, 255, 1)' }}>{COUNTRIES[selectedCountryIdx].official_name}</div>
              <div style={{ display: 'grid', gridTemplateColumns: 'auto 1fr', gap: '6px 16px' }}>
                <span style={{ color: 'rgba(0, 170, 255, 0.8)' }}>ISO:</span><span>{COUNTRIES[selectedCountryIdx].iso2} / {COUNTRIES[selectedCountryIdx].iso3}</span>
                <span style={{ color: 'rgba(0, 170, 255, 0.8)' }}>Capital:</span><span>{COUNTRIES[selectedCountryIdx].capital}</span>
                <span style={{ color: 'rgba(0, 170, 255, 0.8)' }}>Continent:</span><span>{COUNTRIES[selectedCountryIdx].continent}</span>
                <span style={{ color: 'rgba(0, 170, 255, 0.8)' }}>Region:</span><span>{COUNTRIES[selectedCountryIdx].region}</span>
                <span style={{ color: 'rgba(0, 170, 255, 0.8)' }}>Population:</span><span>{COUNTRIES[selectedCountryIdx].population}</span>
                <span style={{ color: 'rgba(0, 170, 255, 0.8)' }}>Area:</span><span>{COUNTRIES[selectedCountryIdx].area_km2} km²</span>
                <span style={{ color: 'rgba(0, 170, 255, 0.8)' }}>GDP:</span><span>{COUNTRIES[selectedCountryIdx].gdp_usd}</span>
                <span style={{ color: 'rgba(0, 170, 255, 0.8)' }}>Currency:</span><span>{COUNTRIES[selectedCountryIdx].currency}</span>
              </div>
              <div style={{ marginTop: '12px', paddingTop: '12px', borderTop: '1px solid rgba(0, 170, 255, 0.4)', fontSize: '14px', color: 'rgba(255, 255, 255, 0.9)' }}>Languages: {COUNTRIES[selectedCountryIdx].languages}</div>
            </div>
          </div>
        </div>
      )}
    </main>
  );
}
