'use client';

import { motion, useAnimationFrame, useMotionValue, useSpring } from 'framer-motion';

interface PlaybackControlsProps {
  isPlaying: boolean;
  progress: number;
  onPlayPause: () => void;
  onProgressChange: (value: number) => void;
  currentTime: string;
  totalTime: string;
  startDate?: string;
  endDate?: string;
  rotationSpeed?: number;
  onRotationSpeedChange?: (speed: number) => void;
}

export default function PlaybackControls({
  isPlaying,
  progress,
  onPlayPause,
  onProgressChange,
  currentTime,
  totalTime,
  startDate,
  endDate,
  rotationSpeed,
  onRotationSpeedChange,
}: PlaybackControlsProps) {
  const x = useMotionValue(0);
  const loopSpeed = useSpring(0, { damping: 20, stiffness: 300 });

  useAnimationFrame((time, delta) => {
    if (!isPlaying) return;
    const speed = rotationSpeed || 0.3;
    const dir = speed >= 0 ? 1 : -1;
    const increment = (delta / 1000) * speed * 50;
    const current = x.get();
    let next = current + increment;
    if (next > 50) next = -50;
    if (next < -50) next = 50;
    x.set(next);
    if (onRotationSpeedChange) onRotationSpeedChange(speed * dir);
  });

  return (
    <motion.div
      initial={{ opacity: 0, y: 50 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5, delay: 0.2 }}
      className="glass-panel p-4 rounded-2xl w-full max-w-2xl text-white"
    >
      <div className="flex items-center gap-4 mb-3">
        <motion.div
          drag="x"
          dragConstraints={{ left: -50, right: 50 }}
          dragElastic={0}
          style={{ x }}
          animate={{ x: isPlaying ? x.get() : 0 }}
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.95 }}
          onClick={onPlayPause}
          className="w-12 h-12 rounded-full bg-gradient-to-r from-blue-500 to-cyan-500 hover:from-blue-600 hover:to-cyan-600 flex items-center justify-center text-xl shadow-lg shadow-blue-500/30 transition-all cursor-pointer"
        >
          {isPlaying ? '⏸' : '▶'}
        </motion.div>

        <div className="flex-1">
          <input
            type="range"
            min="0"
            max="100"
            value={progress * 100}
            onChange={(e) => onProgressChange(parseFloat(e.target.value) / 100)}
            className="w-full accent-blue-500 cursor-pointer"
          />
        </div>

        <div className="text-sm text-gray-300 min-w-[120px] text-right font-mono">
          {currentTime} / {totalTime}
        </div>
      </div>

      {(startDate || endDate) && (
        <div className="flex items-center justify-center gap-4 text-xs text-gray-400 mb-2">
          {startDate && (
            <span>From: {new Date(startDate).toLocaleDateString()}</span>
          )}
          {endDate && (
            <span>To: {new Date(endDate).toLocaleDateString()}</span>
          )}
        </div>
      )}

      <div className="text-xs text-gray-400 text-center">
        Tracking Playback • Click play for oscillating spin, drag left/right to control direction
      </div>
    </motion.div>
  );
}

export default function PlaybackControls({
  isPlaying,
  progress,
  onPlayPause,
  onProgressChange,
  currentTime,
  totalTime,
  startDate,
  endDate,
  rotationSpeed,
  onRotationSpeedChange,
}: PlaybackControlsProps) {
  const handleDrag = (event: any, info: any) => {
    const x = info.point.x;
    const speed = Math.max(-2, Math.min(2, x / 25));
    if (onRotationSpeedChange) onRotationSpeedChange(speed);
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 50 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5, delay: 0.2 }}
      className="glass-panel p-4 rounded-2xl w-full max-w-2xl text-white"
    >
      <div className="flex items-center gap-4 mb-3">
        <motion.div
          drag="x"
          dragConstraints={{ left: -50, right: 50 }}
          dragElastic={0}
          onDrag={handleDrag}
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.95 }}
          onClick={onPlayPause}
          className="w-12 h-12 rounded-full bg-gradient-to-r from-blue-500 to-cyan-500 hover:from-blue-600 hover:to-cyan-600 flex items-center justify-center text-xl shadow-lg shadow-blue-500/30 transition-all cursor-pointer"
          style={{ x: 0 }}
        >
          {isPlaying ? '⏸' : '▶'}
        </motion.div>

        <div className="flex-1">
          <input
            type="range"
            min="0"
            max="100"
            value={progress * 100}
            onChange={(e) => onProgressChange(parseFloat(e.target.value) / 100)}
            className="w-full accent-blue-500 cursor-pointer"
          />
        </div>

        <div className="text-sm text-gray-300 min-w-[120px] text-right font-mono">
          {currentTime} / {totalTime}
        </div>
      </div>

      {(startDate || endDate) && (
        <div className="flex items-center justify-center gap-4 text-xs text-gray-400 mb-2">
          {startDate && (
            <span>From: {new Date(startDate).toLocaleDateString()}</span>
          )}
          {endDate && (
            <span>To: {new Date(endDate).toLocaleDateString()}</span>
          )}
        </div>
      )}

      <div className="text-xs text-gray-400 text-center">
        Tracking Playback • Drag volume left/right to spin globe
      </div>
    </motion.div>
  );
}
